1	const PROCESSING_FEE = 5;
2	const COMPONENT_PREMIUM = 25;
3	const BLOCK_PREMIUM = 60;
4	const BLOCK_SIZE = 3;
5	
6	const BASE_PREMIUMS: Record<string, number> = {
7	  sword: 100,
8	  amulet: 60,
9	  staff: 80,
10	  potion: 40,
11	};
12	
13	const INSURANCE_VALUES: Record<string, number> = {
14	  sword: 1000,
15	  amulet: 600,
16	  staff: 800,
17	  potion: 400,
18	};
19	
20	const COMPONENT_INSURANCE_VALUE = 250;
21	const DEDUCTIBLE = 100;
22	
23	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
24	
25	function countComponentsByType(items: any[]): Record<string, number> {
26	  return items
27	    .filter((item) => COMPONENT_TYPES.has(item.type))
28	    .reduce(
29	      (counts: Record<string, number>, item) => ({
30	        ...counts,
31	        [item.type]: (counts[item.type] ?? 0) + 1,
32	      }),
33	      {},
34	    );
35	}
36	
37	function componentGroupPremium(count: number): number {
38	  return count === BLOCK_SIZE ? BLOCK_PREMIUM : count * COMPONENT_PREMIUM;
39	}
40	
41	function calculateComponentPremium(items: any[]): number {
42	  return Object.values(countComponentsByType(items)).reduce(
43	    (sum, count) => sum + componentGroupPremium(count),
44	    0,
45	  );
46	}
47	
48	function calculateItemPremium(item: any): { base: number; total: number } {
49	  if (COMPONENT_TYPES.has(item.type)) {
50	    return { base: 0, total: 0 };
51	  }
52	  if (!(item.type in BASE_PREMIUMS)) {
53	    throw new Error(`Unknown item type: ${item.type}`);
54	  }
55	  const base = BASE_PREMIUMS[item.type];
56	  const cursedSurcharge = item.cursed ? base * 0.5 : 0;
57	  const enchantmentSurcharge = item.enchantment >= 5 ? base * 0.3 : 0;
58	  return { base, total: base + cursedSurcharge + enchantmentSurcharge };
59	}
60	
61	function calculateQuotePremium(items: any[], customer: any, contractIndex: number): number {
62	  const itemPremiums = items.map((item) => calculateItemPremium(item));
63	  const itemTotal = itemPremiums.reduce((sum, p) => sum + p.total, 0);
64	  const nonComponentBase = itemPremiums.reduce((sum, p) => sum + p.base, 0);
65	  const componentTotal = calculateComponentPremium(items);
66	  const policyBasePremium = nonComponentBase + componentTotal;
67	  const firstInsurance = policyBasePremium * 0.1;
68	  const loyalty = customer.yearsWithMHPCO >= 2 ? policyBasePremium * 0.2 : 0;
69	  const followUp = contractIndex > 0 ? policyBasePremium * 0.15 : 0;
70	  return Math.ceil(PROCESSING_FEE + itemTotal + componentTotal + firstInsurance - loyalty - followUp);
71	}
72	
73	function calculateInsuranceSum(items: any[]): number {
74	  return items.reduce((sum: number, item: any) => {
75	    if (COMPONENT_TYPES.has(item.type)) {
76	      return sum + COMPONENT_INSURANCE_VALUE;
77	    }
78	    return sum + (INSURANCE_VALUES[item.type] ?? 0);
79	  }, 0);
80	}
81	
82	export function processScenario(scenario: any): any {
83	  let quoteIndex = 0;
84	  const policies: Record<number, { items: any[]; remainingCap: number }> = {};
85	  const results = scenario.steps.map((step: any, index: number) => {
86	    if (step.op === "quote") {
87	      const insuranceSum = calculateInsuranceSum(step.items);
88	      policies[index] = { items: step.items, remainingCap: insuranceSum * 2 };
89	      return { premium: calculateQuotePremium(step.items, scenario.customer, quoteIndex++) };
90	    }
91	    if (step.op === "claim") {
92	      const policy = policies[step.policy];
93	      const damageCounts: Record<string, number> = {};
94	      for (const damage of step.incident.damages) {
95	        damageCounts[damage.itemType] = (damageCounts[damage.itemType] ?? 0) + 1;
96	      }
97	      for (const [itemType, count] of Object.entries(damageCounts)) {
98	        const policyCount = policy.items.filter((i: any) => i.type === itemType).length;
99	        if (count > policyCount) {
100	          throw new Error(`More damages of type ${itemType} than policy covers`);
101	        }
102	      }
103	      let totalPayout = 0;
104	      for (const damage of step.incident.damages) {
105	        const item = policy.items.find((i: any) => i.type === damage.itemType);
106	        if (!item) {
107	          throw new Error(`Item type ${damage.itemType} not in policy`);
108	        }
109	        if (damage.amount < 0) {
110	          throw new Error(`Negative damage amount: ${damage.amount}`);
111	        }
112	        let reimbursement = damage.amount;
113	        if (item.enchantment >= 8) {
114	          reimbursement = damage.amount * 0.5;
115	        }
116	        const payout = reimbursement - DEDUCTIBLE;
117	        totalPayout += Math.max(0, payout);
118	      }
119	      totalPayout = Math.min(totalPayout, policy.remainingCap);
120	      policy.remainingCap -= totalPayout;
121	      return { payout: Math.floor(totalPayout), remainingCap: policy.remainingCap };
122	    }
123	  });
124	  return { results };
125	}
