      policies[index] = { items: step.items, remainingCap: insuranceSum * 2 };
      return { premium: calculateQuotePremium(step.items, scenario.customer, quoteIndex++) };
    }
    if (step.op === "claim") {
      return processClaim(step.incident.damages, policies[step.policy]);
    }
  });
  return { results };
}

